/// <summary>
/// extension class for table <c>ITMTTSTable</c>
/// </summary>
[ExtensionOf(tableStr(ITMTTSTable))]
internal final class ETGITMTTSTable_Table_Extension
{
}

Method.Source:
/// <summary>
/// create tts level for outbound orders
/// </summary>
public static void createTTSOutETG()
{
    ITMTTSTable ttsTable;
    CreatedTransactionId ttsId = appl.curTransactionId(true);

    if (!ITMTTSTable::exist(ttsId))
    {
        ttsTable.clear();
        ttsTable.TTSId = ttsId;
        ttsTable.TTSLevel = appl.ttsLevel();
        ttsTable.insert();
    }
}

/// <summary>
/// delete tts level for outbound orders
/// </summary>
public static void deleteTTSOutETG()
{
    ITMTTSTable ttsTable;
    CreatedTransactionId ttsId = appl.curTransactionId(true);
    Level ttsLevel = appl.ttsLevel();

    delete_from ttsTable
        where ttsTable.TTSId == ttsId
            && ttsTable.TTSLevel == ttsLevel;
}
